import{_ as e,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Migração de Contas: Backup/Migração a Quente | Antigravity Manager","description":"Aprenda backup e migração de contas do Antigravity Manager. Suporta importar/exportar JSON, migrar a quente de Antigravity/IDE, migrar de diretório de dados V1, e sincronizar automaticamente conta atual logada.","frontmatter":{"title":"Migração de Contas: Backup/Migração a Quente | Antigravity Manager","sidebarTitle":"Migre Pool de Contas em 3 Minutos","subtitle":"Migração de Contas: Backup/Migração a Quente","description":"Aprenda backup e migração de contas do Antigravity Manager. Suporta importar/exportar JSON, migrar a quente de Antigravity/IDE, migrar de diretório de dados V1, e sincronizar automaticamente conta atual logada.","tags":["Gerenciamento de Contas","Backup","Migração","Importar/Exportar","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function s(n,a,d,c,l,p){return t(),o("div",null,[...a[0]||(a[0]=[r(`<h1 id="backup-e-migracao-de-contas-importar-exportar-migracao-a-quente-v1-db" tabindex="-1">Backup e Migração de Contas: Importar/Exportar, Migração a Quente V1/DB <a class="header-anchor" href="#backup-e-migracao-de-contas-importar-exportar-migracao-a-quente-v1-db" aria-label="Permalink to &quot;Backup e Migração de Contas: Importar/Exportar, Migração a Quente V1/DB&quot;">​</a></h1><p>O que você realmente quer &quot;fazer backup&quot;, na verdade não são números de cota, mas o <code>refresh_token</code> que permite que contas relogue. Esta lição deixa claro vários meios de migração do Antigravity Tools: importar/exportar JSON, importar de <code>state.vscdb</code>, importar de diretório de dados V1, e como funciona sincronização automática.</p><h2 id="o-que-voce-podera-fazer-apos-completar" tabindex="-1">O que você poderá fazer após completar <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-completar" aria-label="Permalink to &quot;O que você poderá fazer após completar&quot;">​</a></h2><ul><li>Exportar pool de contas para um arquivo JSON (só contém email + refresh_token)</li><li>Em nova máquina importar este JSON, recuperar rapidamente pool de contas</li><li>Importar diretamente &quot;conta atual logada&quot; de Antigravity/IDE <code>state.vscdb</code> (suporta caminho padrão e caminho personalizado)</li><li>Importar automaticamente escaneando e lendo contas antigas de diretório de dados V1</li><li>Entender o que &quot;sincronizar conta atual automaticamente&quot; realmente faz, quando pulará</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Após reinstalar sistema/trocar computador, pool de contas precisa ser adicionado novamente, custo alto</li><li>Você mudou conta logada no Antigravity/IDE, mas &quot;conta atual&quot; do Manager não seguiu mudança</li><li>Você usou versão V1/versão script antes, só tem arquivos de dados antigos na mão, não sabe se pode migrar diretamente</li></ul><h2 id="quando-usar-essa-tecnica" tabindex="-1">Quando usar essa técnica <a class="header-anchor" href="#quando-usar-essa-tecnica" aria-label="Permalink to &quot;Quando usar essa técnica&quot;">​</a></h2><ul><li>Você quer mover pool de contas para outra máquina (desktop/servidor/container)</li><li>Você trata Antigravity como &quot;entrada de login autoritativa&quot;, quer Manager sincronizar conta atual automaticamente</li><li>Você quer migrar contas da versão antiga (diretório de dados V1)</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><ul><li>Você já consegue abrir Antigravity Tools, e tem pelo menos uma conta no pool de contas</li><li>Você sabe dados de conta pertencem a informação sensível (especialmente <code>refresh_token</code>)</li></ul><div class="warning custom-block"><p class="custom-block-title">Lembrete de segurança: trate arquivo de backup como senha</p><p>Arquivo JSON exportado contém <code>refresh_token</code>. Qualquer pessoa que tenha ele, pode usá-lo para renovar access token. Não carregue arquivo de backup para link público de nuvem, não mande para grupo, não submeta para Git.</p></div><h2 id="ideia-principal" tabindex="-1">Ideia Principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia Principal&quot;">​</a></h2><p>No fundo, &quot;migração&quot; do Antigravity Tools são apenas duas coisas:</p><ol><li>Encontrar <code>refresh_token</code> disponível</li><li>Usar para trocar access token, e obter email real do Google, depois escrever conta no pool de contas local</li></ol><p>Ele fornece três entradas:</p><ul><li>Importar/Exportar JSON: adequado quando você quer explicitamente fazer &quot;backup controlável&quot;</li><li>Importar DB: adequado quando você trata estado de login Antigravity/IDE como fonte autoritativa (por padrão procura <code>state.vscdb</code>, também suporta escolher arquivo manualmente)</li><li>Importar V1: adequado para escanear automaticamente e migrar de diretório de dados antigo</li></ul><p>Além disso há &quot;sincronização automática&quot;: ela lerá periodicamente refresh_token do DB, se diferente da conta atual do Manager, executará automaticamente uma importação de DB; se igual, pulará diretamente (economiza tráfego).</p><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-exportar-pool-de-contas-backup-json" tabindex="-1">Passo 1: Exportar pool de contas (backup JSON) <a class="header-anchor" href="#passo-1-exportar-pool-de-contas-backup-json" aria-label="Permalink to &quot;Passo 1: Exportar pool de contas (backup JSON)&quot;">​</a></h3><p><strong>Por que</strong> Esta é maneira mais estável e controlável de migração. Você obtém um arquivo, pode recuperar pool de contas em outra máquina.</p><p>Operação: entre na página <code>Accounts</code>, clique botão de exportar.</p><ul><li>Se você configurou <code>default_export_path</code> nas configurações, exportação escreverá diretamente neste diretório, e usará nome de arquivo <code>antigravity_accounts_YYYY-MM-DD.json</code>.</li><li>Se não configurou diretório padrão, surgirá diálogo de salvar do sistema para você escolher caminho.</li></ul><p>Conteúdo do arquivo exportado aproximadamente assim (cada item no array só mantém campos necessários):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>Você deve ver</strong>: Página avisa exportação bem-sucedida, e mostra caminho salvo.</p><h3 id="passo-2-importar-json-em-nova-maquina-recuperar-pool-de-contas" tabindex="-1">Passo 2: Importar JSON em nova máquina (recuperar pool de contas) <a class="header-anchor" href="#passo-2-importar-json-em-nova-maquina-recuperar-pool-de-contas" aria-label="Permalink to &quot;Passo 2: Importar JSON em nova máquina (recuperar pool de contas)&quot;">​</a></h3><p><strong>Por que</strong> Importação chamará lógica &quot;adicionar conta&quot; uma por uma, usa <code>refresh_token</code> para puxar email real e escreve no pool de contas.</p><p>Operação: ainda na página <code>Accounts</code>, clique &quot;Importar JSON&quot;, escolha arquivo que você acabou de exportar.</p><p>Requisitos de formato (deve conter pelo menos 1 registro válido):</p><ul><li>Deve ser array JSON</li><li>Sistema só importará entradas que contenham <code>refresh_token</code> e comecem com <code>1//</code></li></ul><p><strong>Você deve ver</strong>: Após importação completar, contas importadas aparecem na lista de contas.</p><div class="tip custom-block"><p class="custom-block-title">Se você importa enquanto Proxy está rodando</p><p>Cada vez &quot;adicionar conta&quot; com sucesso, backend tentará reload token pool de proxy reverso, fazendo nova conta entrar em vigor imediatamente.</p></div><h3 id="passo-3-importar-conta-atual-logada-de-state-vscdb" tabindex="-1">Passo 3: Importar &quot;conta atual logada&quot; de <code>state.vscdb</code> <a class="header-anchor" href="#passo-3-importar-conta-atual-logada-de-state-vscdb" aria-label="Permalink to &quot;Passo 3: Importar &quot;conta atual logada&quot; de \`state.vscdb\`&quot;">​</a></h3><p><strong>Por que</strong> Às vezes você não quer manter arquivo de backup, só quer &quot;tomar estado de login Antigravity/IDE como referência&quot;. Importação de DB é preparada para este cenário.</p><p>Operação: entre na página <code>Accounts</code>, clique <strong>Add Account</strong>, mude para aba <code>Import</code>:</p><ul><li>Clique &quot;Importar de banco de dados&quot; (usar caminho DB padrão)</li><li>Ou clique &quot;Custom DB (state.vscdb)&quot; para escolher manualmente um arquivo <code>*.vscdb</code></li></ul><p>Caminho DB padrão é cross-platform (também prioriza reconhecer <code>--user-data-dir</code> ou modo portable):</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-EgX_J" id="tab-TWIjdRT" checked><label data-title="macOS" for="tab-TWIjdRT">macOS</label><input type="radio" name="group-EgX_J" id="tab-NQZKBtB"><label data-title="Windows" for="tab-NQZKBtB">Windows</label><input type="radio" name="group-EgX_J" id="tab-EdgbnV9"><label data-title="Linux" for="tab-EdgbnV9">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>Você deve ver</strong>:</p><ul><li>Após importação bem-sucedida, esta conta será automaticamente definida como &quot;conta atual&quot; do Manager</li><li>Sistema disparará automaticamente uma atualização de cota</li></ul><h3 id="passo-4-migrar-de-diretorio-de-dados-v1-importar-versao-antiga" tabindex="-1">Passo 4: Migrar de diretório de dados V1 (importar versão antiga) <a class="header-anchor" href="#passo-4-migrar-de-diretorio-de-dados-v1-importar-versao-antiga" aria-label="Permalink to &quot;Passo 4: Migrar de diretório de dados V1 (importar versão antiga)&quot;">​</a></h3><p><strong>Por que</strong> Se você usou versão V1/versão script antes, Manager permite escanear diretório de dados antigo diretamente e tentar importar.</p><p>Operação: na aba <code>Import</code>, clique &quot;Importar V1&quot;.</p><p>Ele procurará este caminho no seu diretório home (e arquivo de índice dentro):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>Você deve ver</strong>: Após importação completar, contas aparecem na lista; se arquivo de índice não encontrado, backend retornará erro <code>V1 account data file not found</code>.</p><h3 id="passo-5-opcional-habilitar-sincronizar-conta-atual-automaticamente" tabindex="-1">Passo 5 (opcional): Habilitar &quot;sincronizar conta atual automaticamente&quot; <a class="header-anchor" href="#passo-5-opcional-habilitar-sincronizar-conta-atual-automaticamente" aria-label="Permalink to &quot;Passo 5 (opcional): Habilitar &quot;sincronizar conta atual automaticamente&quot;&quot;">​</a></h3><p><strong>Por que</strong> Quando você muda conta logada no Antigravity/IDE, Manager pode detectar se refresh_token no DB mudou em intervalos fixos, e importar automaticamente ao mudar.</p><p>Operação: entre em <code>Settings</code>, habilite <code>auto_sync</code>, e defina <code>sync_interval</code> (unidade: segundos).</p><p><strong>Você deve ver</strong>: Após habilitar, executará uma sincronização imediatamente; depois executar periodicamente por intervalo. Se refresh_token no DB for o mesmo da conta atual, pulará diretamente, não importará repetidamente.</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>Você pode ver contas importadas na lista <code>Accounts</code></li><li>Você pode ver &quot;conta atual&quot; já mudou para a que você espera (importação de DB define automaticamente como atual)</li><li>Após iniciar Proxy, novas contas importadas podem ser usadas normalmente para solicitação (baseado em resultado de chamada real)</li></ul><h2 id="aviso-sobre-armadilhas" tabindex="-1">Aviso sobre armadilhas <a class="header-anchor" href="#aviso-sobre-armadilhas" aria-label="Permalink to &quot;Aviso sobre armadilhas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cenário</th><th>O que você pode fazer (❌)</th><th>Prática recomendada (✓)</th></tr></thead><tbody><tr><td>Segurança do arquivo de backup</td><td>Tratar JSON exportado como arquivo de configuração comum e mandar aleatoriamente</td><td>Tratar JSON como senha, minimizar escopo de transmissão, evitar exposição em rede pública</td></tr><tr><td>Importação de JSON falha</td><td>JSON não é array, ou refresh_token não tem prefixo <code>1//</code></td><td>Use JSON exportado deste projeto como modelo, mantenha nomes de campos e estrutura consistentes</td></tr><tr><td>Importação de DB não encontra dados</td><td>Antigravity nunca logou, ou DB falta <code>jetskiStateSync.agentManagerInitState</code></td><td>Primeiro confirme Antigravity/IDE já logou, depois tente importar; se necessário use Custom DB escolher arquivo certo</td></tr><tr><td>Após importação V1 conta não disponível</td><td>refresh_token antigo inválido</td><td>Delete esta conta depois adicione novamente com OAuth/novo refresh_token (baseado em aviso de erro)</td></tr><tr><td>auto_sync muito frequente</td><td><code>sync_interval</code> definido muito pequeno, escaneia DB frequentemente</td><td>Trate como &quot;acompanhar estado&quot;, defina intervalo para frequência que você pode aceitar</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da lição&quot;">​</a></h2><ul><li>Importar/Exportar JSON é maneira mais controlável de migração: arquivo de backup só retém <code>email + refresh_token</code></li><li>Importar de DB adequado para &quot;tomar conta atual logada Antigravity/IDE como referência&quot;, e definirá automaticamente como conta atual do Manager</li><li>Importar de V1 escaneia <code>~/.antigravity-agent</code> e compatível com múltiplos formatos antigos</li><li>auto_sync compara refresh_token; igual pula, não importará repetidamente</li></ul><h2 id="proximo-aviso-de-licao" tabindex="-1">Próximo aviso de lição <a class="header-anchor" href="#proximo-aviso-de-licao" aria-label="Permalink to &quot;Próximo aviso de lição&quot;">​</a></h2><blockquote><p>Na próxima lição realmente usamos &quot;pool de contas após migração&quot;: <strong><a href="./../proxy-and-first-client/">Iniciar Proxy Reverso Local e Conectar Primeiro Cliente (/healthz + Configuração SDK)</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como iniciar/parar Proxy, e usar <code>/healthz</code> para verificação mínima</li><li>Como configurar Base URL em SDK/cliente</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de código-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Exportar/Importar JSON de Accounts (<code>save_text_file</code> / <code>read_text_file</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Dashboard exportar JSON de contas</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Página Import: botões Importar DB / Custom DB / Importar V1</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>Adicionar conta: ignora email frontend, usa refresh_token para obter email real, atualiza cota automaticamente, Proxy hot reload</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Importação de DB: extrair refresh_token de <code>state.vscdb</code> (ItemTable + base64 + protobuf)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Após importação de DB define automaticamente &quot;conta atual&quot; e atualiza cota</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L495-L511" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>495-511</td></tr><tr><td>auto_sync: compara refresh_token, igual pula diretamente; muda então dispara importação de DB</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>Tarefa de background frontend: chama <code>syncAccountFromDb()</code> periodicamente por <code>sync_interval</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const h=e(i,[["render",s]]);export{m as __pageData,h as default};
